143→    // Display dependency status
144→    displayDependencyStatus(depCheckResult);
145→
146→    // Run wizard if there are missing required dependencies
147→    if (depCheckResult.hasMissing) {
148→      const wizardResult = await runSetupWizard(depCheckResult, {
149→        skipPrompts,
150→      });
151→      wizardRemainingIssues = wizardResult.remainingIssues;
152→    }
153→  } else if (options.skipSetup) {
154→    // User explicitly skipped - show brief status
155→    console.log(
156→      chalk.gray("Skipping dependency setup wizard (--skip-setup)\n"),
157→    );
158→  }
159→
160→  // Fall back to legacy warning system for any remaining issues
161→  const { warnings, suggestions } = checkPrerequisites();
162→
163→  // Only show warnings if wizard didn't already handle them or if there are remaining issues
164→  if (
165→    wizardRemainingIssues.length > 0 ||
166→    (options.skipSetup && warnings.length > 0)
167→  ) {
168→    if (wizardRemainingIssues.length > 0) {
169→      console.log(chalk.yellow("⚠️  Remaining setup issues:\n"));
170→      for (const issue of wizardRemainingIssues) {
171→        console.log(chalk.yellow(`   • ${issue}`));
172→      }
173→      console.log();
174→    } else if (warnings.length > 0) {
175→      console.log(chalk.yellow("⚠️  Prerequisites:\n"));
176→      for (const warning of warnings) {
177→        console.log(chalk.yellow(`   • ${warning}`));
178→      }
179→      for (const suggestion of suggestions.filter(
180→        (s) => !s.startsWith("Optional"),
181→      )) {
182→        console.log(chalk.gray(`     ${suggestion}`));
183→      }
184→      console.log();
185→    }
186→  }
187→
188→  // Check if already initialized
189→  const configExists = await fileExists(".claude/settings.json");
190→  if (configExists && !options.force) {
191→    console.log(
192→      chalk.yellow(
193→        "⚠️  Sequant appears to be already initialized (.claude/settings.json exists)",
194→      ),
195→    );
196→    console.log(chalk.gray("   Use --force to reinitialize\n"));
197→
198→    if (!skipPrompts) {
199→      const { proceed } = await inquirer.prompt([
200→        {
201→          type: "confirm",
202→          name: "proceed",
203→          message: "Continue anyway?",
204→          default: false,
205→        },
206→      ]);
207→      if (!proceed) {
208→        console.log(chalk.gray("Aborted."));
209→        return;
210→      }
211→    }
212→  }
213→
214→  // Detect or prompt for stack
215→  let stack = options.stack;
216→  let additionalStacks: string[] = [];
217→
218→  if (!stack) {
219→    // Check for multi-stack project in interactive mode
220→    const allDetectedStacks = !skipPrompts ? await detectAllStacks() : [];
221→
222→    if (allDetectedStacks.length > 1 && !skipPrompts) {
223→      // Multi-stack project detected - show checkbox selection
224→      console.log(
225→        chalk.blue(
226→          `\n🔍 Detected ${allDetectedStacks.length} stacks in this project:`,
227→        ),
228→      );
229→      for (const ds of allDetectedStacks) {
230→        const location = ds.path ? ` (${ds.path}/)` : " (root)";
231→        console.log(
232→          chalk.gray(
233→            `   • ${STACKS[ds.stack]?.displayName || ds.stack}${location}`,
234→          ),
235→        );
236→      }
237→      console.log();
238→
239→      // Multi-stack selection prompt
240→      const { selectedStacks } = await inquirer.prompt([
241→        {
242→          type: "checkbox",
243→          name: "selectedStacks",
244→          message: "Select stacks to include in your constitution:",
245→          choices: allDetectedStacks.map((ds) => ({
246→            name: `${STACKS[ds.stack]?.displayName || ds.stack}${ds.path ? ` (${ds.path}/)` : " (root)"}`,
247→            value: ds.stack,
248→            checked: true, // Pre-select all detected stacks
249→          })),
250→          validate: (answer: string[]) => {
251→            if (answer.length < 1) {
252→              return "You must select at least one stack.";
253→            }
254→            return true;
255→          },
256→        },
257→      ]);
258→
259→      // First selected stack is the primary
260→      if (selectedStacks.length > 0) {
261→        stack = selectedStacks[0];
262→        additionalStacks = selectedStacks.slice(1);
263→      }
264→
265→      // Confirm or change primary stack if multiple selected
266→      if (selectedStacks.length > 1) {
267→        const { primaryStack } = await inquirer.prompt([
268→          {
269→            type: "list",
270→            name: "primaryStack",
271→            message:
272→              "Which stack should be the primary? (determines dev URL and commands)",
273→            choices: selectedStacks.map((s: string) => ({
274→              name: STACKS[s]?.displayName || s,
275→              value: s,
276→            })),
277→          },
278→        ]);
279→        stack = primaryStack;
280→        additionalStacks = selectedStacks.filter(
281→          (s: string) => s !== primaryStack,
282→        );
283→      }
284→    } else {
285→      // Single stack detection (original behavior)
286→      const detected = await detectStack();
287→      if (detected && skipPrompts) {
288→        stack = detected;
289→        logDefault("Detected stack", stack);
290→      } else if (detected && !skipPrompts) {
291→        const { confirmedStack } = await inquirer.prompt([
292→          {
293→            type: "list",
294→            name: "confirmedStack",
295→            message: `Detected ${detected} project. Is this correct?`,
296→            choices: [
297→              { name: `Yes, use ${detected}`, value: detected },
298→              { name: "No, let me choose", value: null },
299→            ],
300→          },
301→        ]);
302→        stack = confirmedStack;
303→      }
304→
305→      if (!stack && skipPrompts) {
306→        // No detection and skipping prompts: use generic as default
307→        stack = "generic";
308→        logDefault("Using stack", stack);
309→      } else if (!stack) {
310→        const { selectedStack } = await inquirer.prompt([
311→          {
312→            type: "list",
313→            name: "selectedStack",
314→            message: "Select your project stack:",
315→            choices: [
316→              { name: "Next.js / React", value: "nextjs" },
317→              { name: "Astro", value: "astro" },
318→              { name: "SvelteKit", value: "sveltekit" },
319→              { name: "Remix", value: "remix" },
320→              { name: "Nuxt", value: "nuxt" },
321→              { name: "Rust", value: "rust" },
322→              { name: "Python", value: "python" },
323→              { name: "Go", value: "go" },
324→              { name: "Generic (no stack-specific config)", value: "generic" },
325→            ],
326→          },
327→        ]);
328→        stack = selectedStack;
329→      }
330→    }
331→  }
332→
333→  // Display selected stacks
334→  if (additionalStacks.length > 0) {
335→    console.log(chalk.blue(`\n📋 Primary Stack: ${stack}`));
336→    console.log(chalk.blue(`   Additional: ${additionalStacks.join(", ")}`));
337→  } else {
338→    console.log(chalk.blue(`\n📋 Stack: ${stack}`));
339→  }
340→
341→  // Detect package manager
342→  const packageManager = await detectPackageManager();
343→  if (packageManager) {
344→    console.log(chalk.blue(`📦 Package Manager: ${packageManager}`));
345→  }
346→
347→  // Get stack config for default dev URL
348→  const stackConfig = getStackConfig(stack!);
349→  let devUrl = stackConfig.devUrl;
350→
351→  // Prompt for dev URL
352→  if (skipPrompts) {
353→    logDefault("Dev URL", devUrl);
354→  } else {
355→    const { inputDevUrl } = await inquirer.prompt([
356→      {
357→        type: "input",
358→        name: "inputDevUrl",
359→        message: "Development server URL:",
360→        default: devUrl,
361→      },
362→    ]);
363→    devUrl = inputDevUrl;
364→  }
365→
366→  // Show what will be created
367→  console.log(chalk.gray("\nWill create:"));
368→  console.log(chalk.gray("  .claude/"));
369→  console.log(chalk.gray("  ├── skills/         (14 workflow skills)"));
370→  console.log(chalk.gray("  ├── hooks/          (pre/post tool hooks)"));
371→  console.log(chalk.gray("  ├── memory/         (constitution & context)"));
372→  console.log(chalk.gray("  └── settings.json   (hooks configuration)"));
373→  console.log(chalk.gray("  .sequant/"));
374→  console.log(chalk.gray("  ├── settings.json   (run preferences)"));
375→  console.log(chalk.gray("  └── logs/           (workflow run logs)"));
376→  console.log(chalk.gray("  scripts/dev/"));
377→  console.log(chalk.gray("  └── *.sh            (worktree helpers)"));
378→
379→  if (!skipPrompts) {
380→    const { confirm } = await inquirer.prompt([
381→      {
382→        type: "confirm",
383→        name: "confirm",
384→        message: "Proceed with installation?",
385→        default: true,
386→      },
387→    ]);
388→    if (!confirm) {
389→      console.log(chalk.gray("Aborted."));
390→      return;
391→    }
392→  }
393→
394→  // Create directories with spinner
395→  const dirSpinner = ui.spinner("Creating directories...");
396→  dirSpinner.start();
397→  await ensureDir(".claude/skills");
398→  await ensureDir(".claude/hooks");
399→  await ensureDir(".claude/memory");
400→  await ensureDir(".claude/.sequant");
401→  await ensureDir(".sequant/logs");
402→  await ensureDir("scripts/dev");
403→  dirSpinner.succeed("Created directories");
404→
405→  // Update .gitignore
406→  const gitignoreUpdated = await updateGitignore();
407→  if (gitignoreUpdated) {
408→    ui.printStatus("success", "Updated .gitignore with Sequant entries");
409→  }
410→
411→  // Save config with tokens
412→  const configSpinner = ui.spinner("Saving configuration...");
413→  configSpinner.start();
414→  const pmConfig = packageManager
415→    ? getPackageManagerCommands(packageManager)
416→    : getPackageManagerCommands("npm");
417→  const tokens = {
418→    DEV_URL: devUrl,
419→    PM_RUN: pmConfig.run, // e.g., "npm run", "bun run", "yarn", "pnpm run"
420→  };
421→  await saveConfig({
422→    tokens,
423→    stack: stack!,
424→    initialized: new Date().toISOString(),
425→  });
426→  configSpinner.succeed("Saved configuration");
427→
428→  // Save multi-stack configuration if additional stacks selected
429→  if (additionalStacks.length > 0) {
430→    const stackConfig: StackConfigFile = {
431→      primary: { name: stack! },
432→      additional: additionalStacks.map((name) => ({ name })),
433→    };
434→    await saveStackConfig(stackConfig);
435→    console.log(chalk.blue("📋 Saved multi-stack configuration"));
436→  }
437→
438→  // Create default settings
439→  const settingsSpinner = ui.spinner("Creating default settings...");
440→  settingsSpinner.start();
441→  await createDefaultSettings();
442→  settingsSpinner.succeed("Created default settings");
443→
444→  // Copy templates (with symlinks for scripts unless --no-symlinks)
445→  const templatesSpinner = ui.spinner("Copying templates...");
446→  templatesSpinner.start();
447→  const { scriptsSymlinked, symlinkResults } = await copyTemplates(
448→    stack!,
449→    tokens,
450→    {
451→      noSymlinks: options.noSymlinks,
452→      force: options.force,
453→      additionalStacks,
454→    },
455→  );
456→
457→  templatesSpinner.succeed("Copied templates");
458→
459→  // Report symlink status
460→  if (scriptsSymlinked) {
461→    ui.printStatus("success", "Created symlinks for scripts/dev/");
462→  } else if (!options.noSymlinks && symlinkResults) {
463→    // Some symlinks may have fallen back to copies
464→    const fallbacks = symlinkResults.filter((r) => r.fallbackToCopy);
465→    if (fallbacks.length > 0) {
466→      console.log(
467→        chalk.yellow("⚠️  Some scripts were copied instead of symlinked:"),
468→      );
469→      for (const fb of fallbacks) {
470→        console.log(chalk.gray(`   ${fb.path}: ${fb.reason}`));
471→      }
472→    }
473→    const skipped = symlinkResults.filter((r) => r.skipped);
474→    if (skipped.length > 0) {
475→      console.log(
476→        chalk.yellow("⚠️  Some scripts were skipped (existing files found):"),
477→      );
478→      for (const s of skipped) {
479→        console.log(chalk.gray(`   ${s.path}: ${s.reason}`));
480→      }
481→    }
482→  }
483→
484→  // Create manifest
485→  const manifestSpinner = ui.spinner("Creating manifest...");
486→  manifestSpinner.start();
487→  await createManifest(stack!, packageManager ?? undefined);
488→  manifestSpinner.succeed("Created manifest");
489→
490→  // Build optional suggestions section
491→  const optionalSuggestions = suggestions.filter((s) =>
492→    s.startsWith("Optional"),
493→  );
494→  const optionalSection =
495→    optionalSuggestions.length > 0
496→      ? `\n${chalk.bold("Optional improvements:")}\n${optionalSuggestions.map((s) => `  • ${s.replace("Optional: ", "")}`).join("\n")}\n`
497→      : "";
498→
499→  // Build prerequisites reminder if there were remaining issues from wizard or warnings
500→  const hasRemainingIssues =
501→    wizardRemainingIssues.length > 0 || warnings.length > 0;
502→  const prereqReminder = hasRemainingIssues
503→    ? `\n${chalk.yellow("⚠️  Remember to install missing dependencies before using issue workflows.")}\n${chalk.gray("   Run 'sequant doctor' to verify your setup.\n")}`
504→    : "";
505→
506→  // Success message with boxed output
507→  const nextStepsContent = `${chalk.bold("Next steps:")}
508→  1. Review .claude/memory/constitution.md
509→  2. Start using workflow commands:
510→
511→     ${chalk.cyan("/spec 123")}  - Plan implementation
512→     ${chalk.cyan("/exec 123")}  - Implement the feature
513→     ${chalk.cyan("/qa 123")}    - Quality review`;
514→
515→  console.log(
516→    "\n" + ui.successBox("Sequant initialized successfully!", nextStepsContent),
517→  );
518→
519→  if (prereqReminder) {
520→    console.log(prereqReminder);
521→  }
522→
523→  if (optionalSection) {
524→    console.log(optionalSection);
525→  }
526→
527→  console.log(
528→    chalk.gray(
529→      "\nDocumentation: https://github.com/sequant-io/sequant#readme\n",
530→    ),
531→  );
532→}
