/**
 * Codebase Conventions Detector
 *
 * Deterministic analysis of codebase patterns to detect conventions.
 * Used during `sequant init` to generate `.sequant/conventions.json`.
 *
 * Detection methods are simple, observable, and non-AI:
 * - File pattern matching (glob)
 * - Content pattern matching (grep-style)
 * - Configuration file inspection
 */

import { readFile, fileExists, writeFile } from "./fs.js";
import { glob } from "glob";
import { resolve, basename } from "path";

/** Path to conventions file */
export const CONVENTIONS_PATH = ".sequant/conventions.json";

/** A single detected convention */
export interface Convention {
  /** Convention key (e.g., "testFilePattern") */
  key: string;
  /** Detected value */
  value: string;
  /** How the value was determined */
  source: "detected" | "manual";
  /** Brief description of what this convention represents */
  description: string;
}

/** Full conventions file structure */
export interface ConventionsFile {
  detected: Record<string, string>;
  manual: Record<string, string>;
}

/** Result from running detection */
export interface DetectionResult {
  conventions: Convention[];
  /** Number of conventions detected */
  count: number;
}

/**
 * Detect test file pattern used in the codebase.
 * Checks for *.test.*, *.spec.*, and __tests__/ patterns.
 */
async function detectTestFilePattern(
  projectRoot: string,
): Promise<Convention | null> {
  const testFiles = await glob("**/*.test.{ts,tsx,js,jsx}", {
    cwd: projectRoot,
    ignore: ["node_modules/**", "dist/**", ".next/**"],
    nodir: true,
  });
  const specFiles = await glob("**/*.spec.{ts,tsx,js,jsx}", {
    cwd: projectRoot,
    ignore: ["node_modules/**", "dist/**", ".next/**"],
    nodir: true,
  });
  const testDirs = await glob("**/__tests__/**/*.{ts,tsx,js,jsx}", {
    cwd: projectRoot,
    ignore: ["node_modules/**", "dist/**", ".next/**"],
    nodir: true,
  });

  if (testFiles.length >= specFiles.length && testFiles.length >= testDirs.length && testFiles.length > 0) {
    return {
      key: "testFilePattern",
      value: "*.test.{ts,tsx}",
      source: "detected",
      description: "Test files use .test. suffix",
    };
  } else if (specFiles.length > testFiles.length && specFiles.length >= testDirs.length && specFiles.length > 0) {
    return {
      key: "testFilePattern",
      value: "*.spec.{ts,tsx}",
      source: "detected",
      description: "Test files use .spec. suffix",
    };
  } else if (testDirs.length > 0) {
    return {
      key: "testFilePattern",
      value: "__tests__/*.{ts,tsx}",
      source: "detected",
      description: "Tests in __tests__/ directories",
    };
  }

  return null;
}

/**
 * Detect dominant export style: named vs default exports.
 */
async function detectExportStyle(
  projectRoot: string,
): Promise<Convention | null> {
  const srcFiles = await glob("src/**/*.{ts,tsx}", {
    cwd: projectRoot,
    ignore: ["node_modules/**", "dist/**", "**/*.test.*", "**/*.spec.*"],
    nodir: true,
  });

  if (srcFiles.length === 0) return null;

  let namedExports = 0;
  let defaultExports = 0;

  // Sample up to 20 files for performance
  const sampled = srcFiles.slice(0, 20);
  for (const file of sampled) {
    try {
      const content = await readFile(resolve(projectRoot, file));
      const namedMatches = content.match(/export\s+(function|const|class|interface|type|enum)\s/g);
      const defaultMatches = content.match(/export\s+default\s/g);
      namedExports += namedMatches?.length ?? 0;
      defaultExports += defaultMatches?.length ?? 0;
    } catch {
      // Skip files that can't be read
    }
  }

  if (namedExports === 0 && defaultExports === 0) return null;

  const style = namedExports >= defaultExports ? "named" : "default";
  return {
    key: "exportStyle",
    value: style,
    source: "detected",
    description: `Codebase primarily uses ${style} exports`,
  };
}

/**
 * Detect async pattern: async/await vs .then() chains.
 */
async function detectAsyncPattern(
  projectRoot: string,
): Promise<Convention | null> {
  const srcFiles = await glob("src/**/*.{ts,tsx}", {
    cwd: projectRoot,
    ignore: ["node_modules/**", "dist/**", "**/*.test.*", "**/*.spec.*"],
    nodir: true,
  });

  if (srcFiles.length === 0) return null;

  let asyncAwait = 0;
  let thenChains = 0;

  const sampled = srcFiles.slice(0, 20);
  for (const file of sampled) {
    try {
      const content = await readFile(resolve(projectRoot, file));
      const awaitMatches = content.match(/\bawait\s/g);
      const thenMatches = content.match(/\.then\s*\(/g);
      asyncAwait += awaitMatches?.length ?? 0;
      thenChains += thenMatches?.length ?? 0;
    } catch {
      // Skip files that can't be read
    }
  }

  if (asyncAwait === 0 && thenChains === 0) return null;

  const pattern = asyncAwait >= thenChains ? "async/await" : ".then()";
  return {
    key: "asyncPattern",
    value: pattern,
    source: "detected",
    description: `Codebase primarily uses ${pattern} for async operations`,
  };
}

/**
 * Detect package manager from lockfiles.
 */
async function detectPackageManagerConvention(
  projectRoot: string,
): Promise<Convention | null> {
  const lockfiles: [string, string][] = [
    ["bun.lockb", "bun"],
    ["bun.lock", "bun"],
    ["pnpm-lock.yaml", "pnpm"],
    ["yarn.lock", "yarn"],
    ["package-lock.json", "npm"],
  ];

  for (const [lockfile, manager] of lockfiles) {
    if (await fileExists(resolve(projectRoot, lockfile))) {
      return {
        key: "packageManager",
        value: manager,
        source: "detected",
        description: `Detected ${manager} from ${lockfile}`,
      };
    }
  }

  return null;
}

/**
 * Detect TypeScript strictness from tsconfig.json.
 */
async function detectTypeScriptStrictness(
  projectRoot: string,
): Promise<Convention | null> {
  const tsconfigPath = resolve(projectRoot, "tsconfig.json");
  if (!(await fileExists(tsconfigPath))) return null;

  try {
    const content = await readFile(tsconfigPath);
    // Strip comments for JSON parsing (simple approach)
    const stripped = content.replace(/\/\/.*$/gm, "").replace(/\/\*[\s\S]*?\*\//g, "");
    const tsconfig = JSON.parse(stripped);
    const strict = tsconfig?.compilerOptions?.strict;

    return {
      key: "typescriptStrict",
      value: strict ? "strict" : "non-strict",
      source: "detected",
      description: strict
        ? "TypeScript strict mode is enabled"
        : "TypeScript strict mode is not enabled",
    };
  } catch {
    return null;
  }
}

/**
 * Detect project structure patterns (component dirs, source layout).
 */
async function detectProjectStructure(
  projectRoot: string,
): Promise<Convention | null> {
  const structures: [string, string, string][] = [
    ["src/components", "src/components/", "Components in src/components/"],
    ["components", "components/", "Components in root components/"],
    ["app", "app/", "Next.js App Router structure"],
    ["pages", "pages/", "Pages-based routing structure"],
    ["src/pages", "src/pages/", "Pages in src/pages/"],
  ];

  for (const [dir, value, desc] of structures) {
    if (await fileExists(resolve(projectRoot, dir))) {
      return {
        key: "componentDir",
        value,
        source: "detected",
        description: desc,
      };
    }
  }

  return null;
}

/**
 * Detect naming convention from source files.
 */
async function detectNamingConvention(
  projectRoot: string,
): Promise<Convention | null> {
  const srcFiles = await glob("src/**/*.{ts,tsx}", {
    cwd: projectRoot,
    ignore: [
      "node_modules/**",
      "dist/**",
      "**/*.test.*",
      "**/*.spec.*",
      "**/index.*",
    ],
    nodir: true,
  });

  if (srcFiles.length === 0) return null;

  let kebabCase = 0;
  let camelCase = 0;
  let pascalCase = 0;

  for (const file of srcFiles.slice(0, 30)) {
    const name = basename(file).replace(/\.(ts|tsx)$/, "");
    if (/^[a-z]+(-[a-z]+)+$/.test(name)) kebabCase++;
    else if (/^[a-z][a-zA-Z]+$/.test(name)) camelCase++;
    else if (/^[A-Z][a-zA-Z]+$/.test(name)) pascalCase++;
  }

  const max = Math.max(kebabCase, camelCase, pascalCase);
  if (max === 0) return null;

  let convention: string;
  if (kebabCase === max) convention = "kebab-case";
  else if (camelCase === max) convention = "camelCase";
  else convention = "PascalCase";

  return {
    key: "fileNaming",
    value: convention,
    source: "detected",
    description: `Source files primarily use ${convention} naming`,
  };
}

/**
 * Detect semicolon usage.
 */
async function detectSemicolons(
  projectRoot: string,
): Promise<Convention | null> {
  const srcFiles = await glob("src/**/*.{ts,tsx}", {
    cwd: projectRoot,
    ignore: ["node_modules/**", "dist/**", "**/*.test.*", "**/*.spec.*"],
    nodir: true,
  });

  if (srcFiles.length === 0) return null;

  let withSemicolons = 0;
  let withoutSemicolons = 0;

  const sampled = srcFiles.slice(0, 10);
  for (const file of sampled) {
    try {
      const content = await readFile(resolve(projectRoot, file));
      const lines = content.split("\n").filter(
        (l) => l.trim().length > 0 && !l.trim().startsWith("//") && !l.trim().startsWith("*"),
      );
      const semiLines = lines.filter((l) => l.trimEnd().endsWith(";"));
      if (semiLines.length > lines.length / 2) {
        withSemicolons++;
      } else {
        withoutSemicolons++;
      }
    } catch {
      // Skip
    }
  }

  if (withSemicolons === 0 && withoutSemicolons === 0) return null;

  const useSemicolons = withSemicolons >= withoutSemicolons;
  return {
    key: "semicolons",
    value: useSemicolons ? "always" : "minimal",
    source: "detected",
    description: useSemicolons
      ? "Codebase uses semicolons"
      : "Codebase omits semicolons where possible",
  };
}

/**
 * Run all convention detectors against a project root.
 */
export async function detectConventions(
  projectRoot: string,
): Promise<DetectionResult> {
  const detectors = [
    detectTestFilePattern,
    detectExportStyle,
    detectAsyncPattern,
    detectPackageManagerConvention,
    detectTypeScriptStrictness,
    detectProjectStructure,
    detectNamingConvention,
    detectSemicolons,
  ];

  const results = await Promise.all(
    detectors.map((detector) => detector(projectRoot)),
  );

  const conventions = results.filter(
    (result): result is Convention => result !== null,
  );

  return {
    conventions,
    count: conventions.length,
  };
}

/**
 * Load existing conventions file, if it exists.
 */
export async function loadConventions(
  projectRoot: string,
): Promise<ConventionsFile> {
  const filePath = resolve(projectRoot, CONVENTIONS_PATH);
  if (await fileExists(filePath)) {
    try {
      const content = await readFile(filePath);
      return JSON.parse(content) as ConventionsFile;
    } catch {
      // Corrupted file — return empty
    }
  }
  return { detected: {}, manual: {} };
}

/**
 * Save conventions to `.sequant/conventions.json`.
 * Preserves existing `manual` section.
 */
export async function saveConventions(
  projectRoot: string,
  result: DetectionResult,
): Promise<ConventionsFile> {
  const existing = await loadConventions(projectRoot);

  const detected: Record<string, string> = {};
  for (const conv of result.conventions) {
    detected[conv.key] = conv.value;
  }

  const merged: ConventionsFile = {
    detected,
    manual: existing.manual,
  };

  const filePath = resolve(projectRoot, CONVENTIONS_PATH);
  await writeFile(filePath, JSON.stringify(merged, null, 2) + "\n");

  return merged;
}

/**
 * Format conventions for CLI display.
 */
export function formatConventions(conventions: ConventionsFile): string {
  const lines: string[] = [];

  const detectedKeys = Object.keys(conventions.detected);
  if (detectedKeys.length > 0) {
    lines.push("Detected Conventions:");
    for (const key of detectedKeys) {
      lines.push(`  ${key}: ${conventions.detected[key]}`);
    }
  } else {
    lines.push("No conventions detected.");
  }

  const manualKeys = Object.keys(conventions.manual);
  if (manualKeys.length > 0) {
    lines.push("");
    lines.push("Manual Overrides:");
    for (const key of manualKeys) {
      lines.push(`  ${key}: ${conventions.manual[key]}`);
    }
  }

  return lines.join("\n");
}

/**
 * Detect and save conventions in one step.
 * Used by `sequant init`.
 */
export async function detectAndSaveConventions(
  projectRoot: string,
): Promise<DetectionResult> {
  const result = await detectConventions(projectRoot);
  await saveConventions(projectRoot, result);
  return result;
}

