import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import { mkdtemp, rm, mkdir, writeFile as fsWriteFile } from "fs/promises";
import { join } from "path";
import { tmpdir } from "os";
import {
  detectConventions,
  saveConventions,
  loadConventions,
  getMergedConventions,
